mapper.insert:
INSERT INTO HOMPI_CONFIG (
    HOMPI_ID, HOMPI_CONFIG_CODE, HOMPI_CONFIG_CONTENT,
    INSERT_USER_ID
)
VALUES (
    #{hompiId},
    #{hompiConfigCode},
    #{hompiConfigContent},
    #{insertUserId}
)
ON DUPLICATE KEY UPDATE
    HOMPI_CONFIG_CONTENT = #{hompiConfigContent},
    UPDATE_USER_ID = #{updateUserId}

INSERT INTO HOMPI_CONFIG (
    HOMPI_ID, HOMPI_MENU_CODE, AVAIL_STATUS,
    INSERT_USER_ID
)
VALUES (
    #{hompiId},
    #{hompiMenuCode},
    #{availStatus},
    #{insertUserId}
)
ON DUPLICATE KEY UPDATE
    AVAIL_STATUS = #{availStatus},
    UPDATE_USER_ID = #{updateUserId}

INSERT INTO HOMPI_DAILY_STATS (
    HOMPI_ID, DAY_STATS_DATE, TODAY_CNT,
    INSERT_USER_ID
)
VALUES (
    #{hompiId},
    #{dayStatsDate},
    0,
    #{insertUserId}
)
ON DUPLICATE KEY UPDATE
    TODAY_CNT = #{todayCnt},
    UPDATE_USER_ID = #{updateUserId}

